example.code:
from celery import Celery, Task
app = Celery('tasks', broker='redis://localhost:6379/0', backend='redis://localhost:6379/1')
app.conf.update( task_serializer='json', accept_content=['json'], task_acks_late=True, task_reject_on_worker_lost=True, worker_prefetch_multiplier=1, )
class BaseTask(Task): autoretry_for = (Exception,) retry_backoff = True retry_backoff_max = 600 retry_jitter = True max_retries = 5
@app.task(base=BaseTask, bind=True) def process_order(self, order_id: str): order = get_order(order_id) charge_payment(order) send_confirmation(order) return {"status": "completed", "order_id": order_id}
